#!/bin/bash
set -e

echo "🔧 EAS pre-install: Installing App Clip provisioning profile..."

PROFILE_DIR="$HOME/Library/MobileDevice/Provisioning Profiles"
mkdir -p "$PROFILE_DIR"

# Decode and install the App Clip provisioning profile
# Profile: SaintSalLabs App Clip AppStore (WNCLLBZB7X)
# Bundle ID: com.saintvision.saintsallabs.Clip
# Expires: 2027-03-17
python3 << 'PYEOF'
import base64, os
data = ""
decoded = base64.b64decode(data)
out = os.path.join(os.path.expanduser('~'), 'Library', 'MobileDevice', 'Provisioning Profiles', 'saintsallabsclip.mobileprovision')
with open(out, 'wb') as f:
    f.write(decoded)
print('✅ App Clip provisioning profile installed to:', out)
PYEOF

echo "✅ Pre-install complete"
